# Plan: Add `next/geo` Geolocation Utility Module

## Context

Next.js exposes thin public entry-point modules (e.g. `next/server`) that re-export
functionality from compiled source files. The `userAgent` / `userAgentFromString`
helpers in `packages/next/src/server/web/spec-extension/user-agent.ts` are the direct
model for the new geolocation helpers. This plan follows the same three-layer pattern:

```
source (.ts)  →  dist/ (compiled)  →  public entry (.js / .d.ts at package root)
```

---

## Critical Files

| Role | Path |
|---|---|
| Pattern reference – source | `packages/next/src/server/web/spec-extension/user-agent.ts` |
| Pattern reference – JS entry | `packages/next/server.js` |
| Pattern reference – type entry | `packages/next/server.d.ts` |
| Manifest | `packages/next/package.json` (lines 11–76, `files` array) |
| **New – core source** | `packages/next/src/server/web/spec-extension/geo.ts` |
| **New – public JS entry** | `packages/next/geo.js` |
| **New – public types entry** | `packages/next/geo.d.ts` |
| **New – tests** | `packages/next/src/server/web/spec-extension/geo.test.ts` |

---

## Step-by-Step Implementation

### Step 1 – Core source: `geo.ts`

Create `packages/next/src/server/web/spec-extension/geo.ts`:

```typescript
// ── Country name map (at least 10 common codes) ──────────────────────────────
const COUNTRY_NAMES: Record<string, string> = {
  AU: 'Australia',
  BR: 'Brazil',
  CA: 'Canada',
  CN: 'China',
  DE: 'Germany',
  FR: 'France',
  GB: 'United Kingdom',
  IN: 'India',
  JP: 'Japan',
  US: 'United States',
}

// ── Geo interface ─────────────────────────────────────────────────────────────
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

// ── geoFromHeaders ────────────────────────────────────────────────────────────
export function geoFromHeaders(headers: Headers): Geo {
  const get = (name: string): string | undefined =>
    headers.get(name) ?? undefined

  const countryCode =
    get('x-vercel-ip-country') ?? get('cf-ipcountry') ?? undefined

  return {
    city: get('x-vercel-ip-city'),
    countryCode,
    country: countryCode !== undefined ? COUNTRY_NAMES[countryCode] : undefined,
    region: get('x-vercel-ip-country-region'),
    latitude: get('x-vercel-ip-latitude'),
    longitude: get('x-vercel-ip-longitude'),
    timezone: get('x-vercel-ip-timezone'),
  }
}

// ── geo (mirrors userAgent signature: accepts { headers: Headers }) ────────────
export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

// ── isInRegion ────────────────────────────────────────────────────────────────
export function isInRegion(geo: Geo, regions: string[]): boolean {
  if (!geo.countryCode) return false
  const code = geo.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

// ── geoDistance (Haversine, km) ───────────────────────────────────────────────
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth radius in km
  const toRad = (deg: number): number => (deg * Math.PI) / 180

  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const Δφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const Δλ = toRad(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(Δφ / 2) ** 2 +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) ** 2

  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}
```

Key design notes:
- `COUNTRY_NAMES` is `Record<string, string>` (not `Record<string, string | undefined>`), so TypeScript returns `string | undefined` from lookup only because the index type allows it — use `?? undefined` pattern.
- All optional fields are `string | undefined`, never `null`, matching strict mode.
- `countryCode` preference order: `x-vercel-ip-country` → `cf-ipcountry`.
- `country` is derived only when `countryCode` is present.

---

### Step 2 – Public JS entry: `geo.js`

Create `packages/next/geo.js` following the exact same pattern as `server.js`:

```javascript
const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders: require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
module.exports = geoExports

exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance
```

---

### Step 3 – Type definitions: `geo.d.ts`

Create `packages/next/geo.d.ts` following the same pattern as `server.d.ts`:

```typescript
export type { Geo } from 'next/dist/server/web/spec-extension/geo'
export { geo } from 'next/dist/server/web/spec-extension/geo'
export { geoFromHeaders } from 'next/dist/server/web/spec-extension/geo'
export { isInRegion } from 'next/dist/server/web/spec-extension/geo'
export { geoDistance } from 'next/dist/server/web/spec-extension/geo'
```

Note: `Geo` is an interface (type-only), use `export type`.

---

### Step 4 – Register in `package.json`

In `packages/next/package.json`, insert `geo.js` and `geo.d.ts` into the `files` array.
Place them **after** `form.js` / `form.d.ts` (lines 42–43) because `g` sorts after `f`:

```json
    "form.js",
    "form.d.ts",
    "geo.js",          ← add
    "geo.d.ts",        ← add
    "router.js",
```

---

### Step 5 – Test file: `geo.test.ts`

Create `packages/next/src/server/web/spec-extension/geo.test.ts` using **Jest**
(matching the project's existing test infrastructure — all nearby tests in
`spec-extension/adapters/` use `describe`/`it`/`expect` from Jest):

```typescript
import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
} from './geo'

describe('geo()', () => {
  it('extracts Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })
    const result = geo({ headers })
    expect(result.city).toBe('San Francisco')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('CA')
    expect(result.latitude).toBe('37.7749')
    expect(result.longitude).toBe('-122.4194')
    expect(result.timezone).toBe('America/Los_Angeles')
  })

  it('returns undefined fields when headers are absent', () => {
    const result = geo({ headers: new Headers() })
    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
  })
})

describe('geoFromHeaders()', () => {
  it('uses cf-ipcountry as fallback for countryCode', () => {
    const headers = new Headers({ 'cf-ipcountry': 'GB' })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('returns undefined country for unknown countryCode', () => {
    const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches (case-insensitive)', () => {
    expect(isInRegion({ countryCode: 'US' }, ['us', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'ca' }, ['US', 'CA'])).toBe(true)
  })

  it('returns false when countryCode does not match', () => {
    expect(isInRegion({ countryCode: 'DE' }, ['US', 'GB'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US'])).toBe(false)
  })
})

describe('geoDistance()', () => {
  it('calculates New York to London within 50 km tolerance', () => {
    // New York: 40.7128, -74.0060  |  London: 51.5074, -0.1278
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(dist).toBeGreaterThan(5520)
    expect(dist).toBeLessThan(5620)
  })

  it('returns 0 for identical coordinates', () => {
    expect(geoDistance('40.0', '-74.0', '40.0', '-74.0')).toBe(0)
  })
})
```

---

## Verification

After implementation (no build step needed to check types only):

```bash
# 1. Type-check only (fast, ~10s)
pnpm --filter=next types

# 2. Run unit tests
pnpm test-unit packages/next/src/server/web/spec-extension/geo.test.ts

# 3. Full build (generates dist/ so geo.js can require from it)
pnpm --filter=next build

# 4. Smoke-test the public entry resolves
node -e "const g = require('./packages/next/geo.js'); console.log(Object.keys(g))"
# Expected: [ 'geo', 'geoFromHeaders', 'isInRegion', 'geoDistance' ]
```

